input.command:
perl -pi -e '
s/→ PostgreSQL schema registry/→ Redis schema registry (ADR 0001 — Redis-only metadata)/;
s/\QPer-token rate limiting (Redis counter, `RATE_LIMIT` in `.pipe` file)\E/Per-token rate limiting (in-memory `httprate` sliding-window, ADR 0015; `RATE_LIMIT` in `.pipe` file)/;
s/\QAdd-ons: `heroku-postgresql:mini`, `heroku-redis:mini`\E/Add-ons: `heroku-redis:mini` (ClickHouse external; no Postgres — ADR 0001)/;
s/EC2, RDS PostgreSQL, Elastic IP/EC2, ElastiCache Redis, Elastic IP/;
s/\QInstanceType` (default `t3.medium`), RDS credentials, `ClickHouseEndpoint`\E/InstanceType` (default `t3.medium`), `RedisEndpoint`, `ClickHouseEndpoint`/;
s/includes ClickHouse \+ TinyRaven \+ Redis \+ PostgreSQL/includes ClickHouse + TinyRaven + Redis/;
' MILESTONE.md
echo "---verify no stale metadata Postgres remains (176 connector is OK)---"; grep -n "PostgreSQL\|Postgres\|Redis counter\|RDS" MILESTONE.md

perl -pi -e '
s/\QKafka connector (consumer group, offset management, schema mapping)\E/Kafka source: `.datasource` template for `ENGINE = Kafka(...)` + MV — ClickHouse runs the consumer (ADR 0019, not a built connector)/;
s/\QS3 connector (batch import, scheduled `COPY` pipes)\E/S3 \/ files: `.datasource` templates for `s3()`\/`url()`\/`file()` + `ENGINE = S3` (ADR 0019)/;
s/\QPostgreSQL connector (table function, optional CDC via logical replication)\E/PostgreSQL: `ENGINE = PostgreSQL(...)` \/ `postgresql()` table function, optional CDC via `MaterializedPostgreSQL` (ADR 0019)/;
s/\Q# → 202 Accepted {"status":"ok"}   (ack-on-buffer; see docs/adr/0004)\E/# → 202 {"successful_rows":1,"quarantined_rows":0}   (ack-on-buffer ADR 0004; quarantine ADR 0018)/;
' MILESTONE.md
echo "verify:"; grep -n "Kafka source\|ENGINE = S3\|ENGINE = PostgreSQL\|successful_rows\|CONNECTOR = kafka" MILESTONE.md
